use anyhow::{Context, Result};
use std::collections::BTreeMap;
use tree_sitter::{Node, Parser};

use crate::cfg::{CfgNodeId, CfgNodeKind, ControlFlowGraph, FunctionParam, ResourceKind};
use crate::extractors::ir::{
    build_declaration_props as ir_build_declaration_props,
    build_entry_props as ir_build_entry_props,
    build_expression_statement_props as ir_build_expression_statement_props,
    build_return_props as ir_build_return_props, ir_as_simple_ident, ir_call_callee_args,
};
use crate::extractors::LanguageExtractor;
use crate::source_map::SourceSpan;

pub struct GoExtractor;

impl LanguageExtractor for GoExtractor {
    fn language_id(&self) -> &str {
        "go"
    }

    fn file_extensions(&self) -> &[&str] {
        &[".go"]
    }

    fn extract(&self, source: &str, file_path: &str) -> Result<Vec<ControlFlowGraph>> {
        let mut parser = Parser::new();
        let language = tree_sitter_go::LANGUAGE.into();
        parser
            .set_language(&language)
            .context("failed to set Go grammar")?;

        let tree = parser
            .parse(source, None)
            .context("failed to parse Go source")?;

        let root = tree.root_node();
        let mut cfgs = Vec::new();

        extract_go_functions(&root, source, file_path, &mut cfgs)?;

        Ok(cfgs)
    }
}

fn extract_go_functions(
    node: &Node,
    source: &str,
    file_path: &str,
    cfgs: &mut Vec<ControlFlowGraph>,
) -> Result<()> {
    let preamble = if node.kind() == "source_file" {
        collect_go_preamble(node, source)
    } else {
        None
    };
    extract_go_functions_with_preamble(node, source, file_path, cfgs, preamble.as_deref())
}

fn extract_go_functions_with_preamble(
    node: &Node,
    source: &str,
    file_path: &str,
    cfgs: &mut Vec<ControlFlowGraph>,
    module_preamble: Option<&str>,
) -> Result<()> {
    if node.kind() == "function_declaration" || node.kind() == "method_declaration" {
        let name = node
            .child_by_field_name("name")
            .map(|n| node_text(n, source))
            .unwrap_or_else(|| "anonymous".to_string());

        let cfg = extract_go_function_cfg(node, source, file_path, &name, module_preamble)?;
        cfgs.push(cfg);
    }

    for i in 0..node.child_count() {
        if let Some(child) = node.child(i) {
            extract_go_functions_with_preamble(&child, source, file_path, cfgs, module_preamble)?;
        }
    }

    Ok(())
}

/// Lift Go top-level `var`/`const` declarations into a JSON-encoded preamble.
/// Recognizes `var X = expr`, `const X = expr`, and grouped forms `var ( X = ... )`.
fn collect_go_preamble(root: &Node, source: &str) -> Option<String> {
    let mut decls: Vec<serde_json::Value> = Vec::new();
    let mut cursor = root.walk();
    for child in root.named_children(&mut cursor) {
        match child.kind() {
            "var_declaration" | "const_declaration" => {
                // Both grouped (`var ( X = 1 )`) and single (`var X = 1`) shapes
                // contain `var_spec` / `const_spec` children with `name` and
                // `value` fields.
                let mut spec_cursor = child.walk();
                for spec in child.named_children(&mut spec_cursor) {
                    if spec.kind() != "var_spec" && spec.kind() != "const_spec" {
                        continue;
                    }
                    let name_node = spec.child_by_field_name("name");
                    let value_node = spec.child_by_field_name("value");
                    if let (Some(n), Some(v)) = (name_node, value_node) {
                        if n.kind() == "identifier" {
                            let bind = node_text(n, source);
                            // Go's value field can be an expression_list for
                            // multi-bind. For this pass we only capture the
                            // first expression; multi-bind is rare at the
                            // top level.
                            let expr_node = if v.kind() == "expression_list" {
                                v.named_child(0).unwrap_or(v)
                            } else {
                                v
                            };
                            let expr_ir = go_node_to_ir(&expr_node, source);
                            decls.push(serde_json::json!({ "bind": bind, "expr": expr_ir }));
                        }
                    }
                }
            }
            _ => {}
        }
    }
    if decls.is_empty() {
        None
    } else {
        Some(serde_json::Value::Array(decls).to_string())
    }
}

fn extract_go_function_cfg(
    func_node: &Node,
    source: &str,
    file_path: &str,
    name: &str,
    module_preamble: Option<&str>,
) -> Result<ControlFlowGraph> {
    let mut cfg = ControlFlowGraph::new(name.to_string(), "go".to_string(), file_path.to_string());

    // Extract Go function signature.
    // Go: func (receiver) name(params) (returns) { body }
    if let Some(params_node) = func_node.child_by_field_name("parameters") {
        extract_go_params(&params_node, source, &mut cfg.signature.params);
    }
    if let Some(result_node) = func_node.child_by_field_name("result") {
        cfg.signature.return_type = Some(node_text(result_node, source));
    }
    // Method receiver.
    if func_node.kind() == "method_declaration" {
        if let Some(receiver) = func_node.child_by_field_name("receiver") {
            cfg.signature.receiver_type = Some(node_text(receiver, source));
        }
    }
    // Extract callees.
    if let Some(body_node) = func_node.child_by_field_name("body") {
        extract_go_callees(&body_node, source, &mut cfg.signature.callees);
    }

    let mut entry_props = ir_build_entry_props(&cfg.signature.params);
    if let Some(preamble_json) = module_preamble {
        entry_props.insert("module_preamble".to_string(), preamble_json.to_string());
    }
    let entry = cfg.add_node_with_props(
        CfgNodeKind::Entry {
            name: name.to_string(),
        },
        SourceSpan::from_tree_sitter(file_path, func_node),
        format!("func {name}"),
        entry_props,
    );
    cfg.entry = entry;

    let body = func_node.child_by_field_name("body").unwrap_or(*func_node);

    let last = extract_go_body(&body, source, file_path, &mut cfg, entry)?;

    if let Some(last_id) = last {
        if !matches!(cfg.nodes[last_id].kind, CfgNodeKind::Return) {
            let ret = cfg.add_node(
                CfgNodeKind::Return,
                SourceSpan::from_tree_sitter(file_path, &body),
                "implicit return".to_string(),
            );
            cfg.add_edge(last_id, ret, None);
            cfg.exits.push(ret);
        }
    } else {
        let ret = cfg.add_node(
            CfgNodeKind::Return,
            SourceSpan::from_tree_sitter(file_path, &body),
            "implicit return".to_string(),
        );
        cfg.add_edge(entry, ret, None);
        cfg.exits.push(ret);
    }

    Ok(cfg)
}

/// Walk an `expression_case` / `default_case` body. Go's tree-sitter shape
/// here is flat — the case keyword, optional value, `:`, then body statements
/// are all named children. We skip the case-machinery (the `value` field for
/// expression_case; nothing for default_case) and feed each remaining named
/// statement child through extract_go_body so it gets the same emission as
/// any statement at function scope.
fn extract_go_case_body(
    case: &Node,
    source: &str,
    file_path: &str,
    cfg: &mut ControlFlowGraph,
    entry: CfgNodeId,
) -> Result<Option<CfgNodeId>> {
    let value_node_id = case.child_by_field_name("value").map(|v| v.id());
    let mut last: Option<CfgNodeId> = Some(entry);
    let mut cursor = case.walk();
    for child in case.named_children(&mut cursor) {
        // Skip the case-value (expression_case only); default_case has none.
        if Some(child.id()) == value_node_id {
            continue;
        }
        // tree-sitter-go wraps case values in an `expression_list` rather than
        // exposing them via the `value` field. Skip it so we don't emit dead
        // statement nodes for the case selector.
        if child.kind() == "expression_list" {
            continue;
        }
        if let Some(prev) = last {
            // Reuse extract_go_body to drop the statement chain in. Pass the
            // child as the root; extract_go_body handles return/statement/etc.
            let end = extract_go_body(&child, source, file_path, cfg, prev)?;
            if end.is_some() {
                last = end;
            }
        }
    }
    Ok(last)
}

fn extract_go_body(
    body: &Node,
    source: &str,
    file_path: &str,
    cfg: &mut ControlFlowGraph,
    predecessor: usize,
) -> Result<Option<usize>> {
    let mut current = predecessor;

    for i in 0..body.child_count() {
        let child = match body.child(i) {
            Some(c) => c,
            None => continue,
        };

        match child.kind() {
            "if_statement" => {
                let has_else = child.child_by_field_name("alternative").is_some();
                let branch = cfg.add_node(
                    CfgNodeKind::Branch {
                        exhaustive: has_else,
                    },
                    SourceSpan::from_tree_sitter(file_path, &child),
                    node_text_truncated(&child, source, 40),
                );
                cfg.add_edge(current, branch, None);

                let merge = cfg.add_node(
                    CfgNodeKind::Merge,
                    SourceSpan::from_tree_sitter(file_path, &child),
                    "if merge".to_string(),
                );

                if let Some(consequence) = child.child_by_field_name("consequence") {
                    let then_end = extract_go_body(&consequence, source, file_path, cfg, branch)?;
                    if let Some(te) = then_end {
                        cfg.add_edge(te, merge, None);
                    }
                }

                if let Some(alternative) = child.child_by_field_name("alternative") {
                    let else_end = extract_go_body(&alternative, source, file_path, cfg, branch)?;
                    if let Some(ee) = else_end {
                        cfg.add_edge(ee, merge, None);
                    }
                } else {
                    cfg.add_edge(branch, merge, Some("no-else".into()));
                }

                current = merge;
            }

            "expression_switch_statement" => {
                // Lower `switch SUBJECT { case A: ...; case B: ...; default: ... }`
                // into a chain of Branch nodes, each carrying `expr` IR for
                // `subject === case_value`. Mirrors the TS lowering so gnexec's
                // IR-driven Branch handler reads the same property shape across
                // languages.
                let merge = cfg.add_node(
                    CfgNodeKind::Merge,
                    SourceSpan::from_tree_sitter(file_path, &child),
                    "switch merge".to_string(),
                );
                let subject_node = child.child_by_field_name("value");
                let has_subject = subject_node.is_some();
                let subject_ir = subject_node
                    .map(|n| go_node_to_ir(&n, source))
                    .unwrap_or(serde_json::Value::Null);

                let mut prev_branch: Option<usize> = None;
                let mut default_body_end: Option<usize> = None;
                let mut cases_collected = false;

                let mut case_cursor = child.walk();
                for case in child.named_children(&mut case_cursor) {
                    cases_collected = true;
                    match case.kind() {
                        "expression_case" => {
                            // tree-sitter-go wraps case values in an
                            // `expression_list`. Single-value: list with one
                            // child. Multi-value (`case 401, 403:`): list with
                            // N children. Tag-less switch: list contains the
                            // full boolean expression.
                            //
                            // Collect every expression-shaped value as IR.
                            let mut value_irs: Vec<serde_json::Value> = Vec::new();
                            let mut vc = case.walk();
                            for c in case.named_children(&mut vc) {
                                let k = c.kind();
                                if k.ends_with("_statement") || k == "block" {
                                    break;
                                }
                                if k == "expression_list" {
                                    let mut lc = c.walk();
                                    for lit in c.named_children(&mut lc) {
                                        value_irs.push(go_node_to_ir(&lit, source));
                                    }
                                } else {
                                    // Defensive fallback for grammars that
                                    // emit the expression directly without a
                                    // wrapping list.
                                    value_irs.push(go_node_to_ir(&c, source));
                                }
                            }
                            if value_irs.is_empty() {
                                value_irs.push(serde_json::Value::Null);
                            }

                            // Build per-value condition. Tag-less switch
                            // (`switch { case x < y: ... }`) carries the full
                            // boolean expression in the case — emit it as-is
                            // rather than wrapping it in a synthetic
                            // `null === expr`.
                            let make_cond = |v: serde_json::Value| -> serde_json::Value {
                                if has_subject {
                                    serde_json::json!({
                                        "kind": "binary",
                                        "op": "===",
                                        "lhs": subject_ir.clone(),
                                        "rhs": v,
                                    })
                                } else {
                                    v
                                }
                            };

                            // Left-fold per-value conditions into an OR chain.
                            let mut iter = value_irs.into_iter();
                            let mut cond_ir = make_cond(iter.next().unwrap());
                            for v in iter {
                                let rhs = make_cond(v);
                                cond_ir = serde_json::json!({
                                    "kind": "binary",
                                    "op": "||",
                                    "lhs": cond_ir,
                                    "rhs": rhs,
                                });
                            }
                            let mut props = std::collections::BTreeMap::new();
                            props.insert("expr".to_string(), cond_ir.to_string());
                            let branch = cfg.add_node_with_props(
                                CfgNodeKind::Branch { exhaustive: false },
                                SourceSpan::from_tree_sitter(file_path, &case),
                                node_text_truncated(&case, source, 40),
                                props,
                            );
                            // Link the previous branch's false-edge to this one.
                            if let Some(prev) = prev_branch {
                                cfg.add_edge(prev, branch, None);
                            } else {
                                cfg.add_edge(current, branch, None);
                            }
                            // True-edge: the case body — Go's expression_case has
                            // no `body` field; body statements are siblings of
                            // the value. Walk a synthetic block by iterating the
                            // case's named children, skipping the value (which
                            // we've already extracted). Wire each as we go.
                            let body_end =
                                extract_go_case_body(&case, source, file_path, cfg, branch)?;
                            if let Some(be) = body_end {
                                cfg.add_edge(be, merge, None);
                            }
                            prev_branch = Some(branch);
                        }
                        "default_case" => {
                            // Capture the default body; we'll wire it as the
                            // false-edge of the last branch (or directly off
                            // current if there were no cases).
                            let body_start = cfg.add_node(
                                CfgNodeKind::Statement,
                                SourceSpan::from_tree_sitter(file_path, &case),
                                "default".to_string(),
                            );
                            let body_end =
                                extract_go_case_body(&case, source, file_path, cfg, body_start)?;
                            // Wire body_start as the false-edge target of the
                            // most recent branch (or current if none).
                            if let Some(prev) = prev_branch {
                                cfg.add_edge(prev, body_start, None);
                            } else {
                                cfg.add_edge(current, body_start, None);
                            }
                            default_body_end = body_end;
                        }
                        _ => {}
                    }
                }

                // Wire the LAST branch's false-edge to merge (if no default).
                if default_body_end.is_none() {
                    if let Some(prev) = prev_branch {
                        cfg.add_edge(prev, merge, None);
                    }
                }
                if let Some(de) = default_body_end {
                    cfg.add_edge(de, merge, None);
                }
                if !cases_collected {
                    // Empty switch: just connect current to merge.
                    cfg.add_edge(current, merge, None);
                }

                current = merge;
            }
            "type_switch_statement" => {
                // Type switch (`switch v := x.(type) { case int: ... }`) is
                // structurally distinct — case values are TYPES not values, and
                // gnexec doesn't have a runtime type system to dispatch on.
                // Keep the legacy fan-out shape; gnexec will fall through to
                // raw byte-range fallback or report IrNotSupported.
                let branch = cfg.add_node(
                    CfgNodeKind::Branch { exhaustive: false },
                    SourceSpan::from_tree_sitter(file_path, &child),
                    node_text_truncated(&child, source, 40),
                );
                cfg.add_edge(current, branch, None);

                let merge = cfg.add_node(
                    CfgNodeKind::Merge,
                    SourceSpan::from_tree_sitter(file_path, &child),
                    "type_switch merge".to_string(),
                );

                let mut case_cursor = child.walk();
                for case in child.named_children(&mut case_cursor) {
                    if case.kind() == "type_case" || case.kind() == "default_case" {
                        let case_end = extract_go_body(&case, source, file_path, cfg, branch)?;
                        if let Some(ce) = case_end {
                            cfg.add_edge(ce, merge, None);
                        }
                    }
                }

                current = merge;
            }

            "for_statement" => {
                let text = node_text(child, source);
                // Go's `for` with no condition is unbounded (`for { ... }`).
                // `for range` and C-style `for` with comparison are bounded.
                let bounded = text.contains("range")
                    || (text.contains(";")
                        && (text.contains(" < ")
                            || text.contains(" <= ")
                            || text.contains(" > ")
                            || text.contains(" >= ")));
                let loop_node = cfg.add_node(
                    CfgNodeKind::Loop { bounded },
                    SourceSpan::from_tree_sitter(file_path, &child),
                    node_text_truncated(&child, source, 40),
                );
                cfg.add_edge(current, loop_node, None);

                if let Some(loop_body) = child.child_by_field_name("body") {
                    let body_end = extract_go_body(&loop_body, source, file_path, cfg, loop_node)?;
                    if let Some(be) = body_end {
                        cfg.add_edge(be, loop_node, Some("back".into()));
                    }
                }

                let exit = cfg.add_node(
                    CfgNodeKind::Merge,
                    SourceSpan::from_tree_sitter(file_path, &child),
                    "for exit".to_string(),
                );
                cfg.add_edge(loop_node, exit, Some("exit".into()));
                current = exit;
            }

            "select_statement" => {
                // select is Go's concurrent RACE.
                let branch = cfg.add_node(
                    CfgNodeKind::Branch { exhaustive: false },
                    SourceSpan::from_tree_sitter(file_path, &child),
                    "select".to_string(),
                );
                cfg.add_edge(current, branch, None);

                let merge = cfg.add_node(
                    CfgNodeKind::Merge,
                    SourceSpan::from_tree_sitter(file_path, &child),
                    "select merge".to_string(),
                );

                for j in 0..child.child_count() {
                    if let Some(case) = child.child(j) {
                        if case.kind() == "communication_case" || case.kind() == "default_case" {
                            let case_end = extract_go_body(&case, source, file_path, cfg, branch)?;
                            if let Some(ce) = case_end {
                                cfg.add_edge(ce, merge, None);
                            }
                        }
                    }
                }

                current = merge;
            }

            "go_statement" => {
                // goroutine launch = FORK.
                let spawn = cfg.add_node(
                    CfgNodeKind::ConcurrentSpawn,
                    SourceSpan::from_tree_sitter(file_path, &child),
                    node_text_truncated(&child, source, 40),
                );
                cfg.add_edge(current, spawn, None);
                current = spawn;
            }

            "defer_statement" => {
                // defer = resource release at function exit.
                let text = node_text(child, source);
                let kind = if text.contains(".Close()") || text.contains(".close()") {
                    CfgNodeKind::ResourceRelease {
                        resource_kind: ResourceKind::Generic("deferred".to_string()),
                    }
                } else if text.contains(".Unlock()") || text.contains(".RUnlock()") {
                    CfgNodeKind::LockRelease { lock_id: None }
                } else {
                    CfgNodeKind::Statement
                };
                let stmt = cfg.add_node(
                    kind,
                    SourceSpan::from_tree_sitter(file_path, &child),
                    node_text_truncated(&child, source, 60),
                );
                cfg.add_edge(current, stmt, None);
                current = stmt;
            }

            "return_statement" => {
                let extra = build_return_props_go(&child, source);
                let ret = cfg.add_node_with_props(
                    CfgNodeKind::Return,
                    SourceSpan::from_tree_sitter(file_path, &child),
                    node_text_truncated(&child, source, 60),
                    extra,
                );
                cfg.add_edge(current, ret, None);
                cfg.exits.push(ret);
                return Ok(Some(ret));
            }

            "short_var_declaration" | "var_declaration" | "assignment_statement" => {
                let node_kind = classify_go_declaration(&child, source);
                let extra = build_go_declaration_props(&child, source);
                let stmt = cfg.add_node_with_props(
                    node_kind,
                    SourceSpan::from_tree_sitter(file_path, &child),
                    node_text_truncated(&child, source, 60),
                    extra,
                );
                cfg.add_edge(current, stmt, None);
                current = stmt;
            }

            "expression_statement" => {
                let node_kind = classify_go_expression(&child, source);
                let extra = build_expression_statement_props_go(&child, source);
                let stmt = cfg.add_node_with_props(
                    node_kind,
                    SourceSpan::from_tree_sitter(file_path, &child),
                    node_text_truncated(&child, source, 60),
                    extra,
                );
                cfg.add_edge(current, stmt, None);
                current = stmt;
            }

            "comment" | "{" | "}" => {}

            _ => {
                let stmt = cfg.add_node(
                    CfgNodeKind::Statement,
                    SourceSpan::from_tree_sitter(file_path, &child),
                    node_text_truncated(&child, source, 60),
                );
                cfg.add_edge(current, stmt, None);
                current = stmt;
            }
        }
    }

    Ok(Some(current))
}

fn classify_go_declaration(node: &Node, source: &str) -> CfgNodeKind {
    let text = node_text(*node, source);

    // File/resource open.
    if text.contains("os.Open") || text.contains("os.Create") || text.contains("os.OpenFile") {
        return CfgNodeKind::ResourceAcquire {
            resource_kind: ResourceKind::File,
        };
    }
    if text.contains("net.Dial") || text.contains("net.Listen") {
        return CfgNodeKind::ResourceAcquire {
            resource_kind: ResourceKind::Socket,
        };
    }
    if text.contains("sql.Open") || text.contains(".Connect(") {
        return CfgNodeKind::ResourceAcquire {
            resource_kind: ResourceKind::Connection,
        };
    }

    // Channel creation.
    if text.contains("make(chan") {
        return CfgNodeKind::ResourceAcquire {
            resource_kind: ResourceKind::Channel,
        };
    }

    // Lock acquire.
    if text.contains(".Lock()") || text.contains(".RLock()") {
        return CfgNodeKind::LockAcquire { lock_id: None };
    }

    CfgNodeKind::Statement
}

fn classify_go_expression(node: &Node, source: &str) -> CfgNodeKind {
    let text = node_text(*node, source);

    if text.contains(".Close()") || text.contains(".close()") {
        return CfgNodeKind::ResourceRelease {
            resource_kind: ResourceKind::Generic("resource".to_string()),
        };
    }

    if text.contains(".Lock()") || text.contains(".RLock()") {
        return CfgNodeKind::LockAcquire { lock_id: None };
    }

    if text.contains(".Unlock()") || text.contains(".RUnlock()") {
        return CfgNodeKind::LockRelease { lock_id: None };
    }

    // WaitGroup.Wait = sync join.
    if text.contains(".Wait()") {
        return CfgNodeKind::SyncJoin;
    }

    CfgNodeKind::Statement
}

fn extract_go_params(params_node: &Node, source: &str, params: &mut Vec<FunctionParam>) {
    for i in 0..params_node.child_count() {
        if let Some(child) = params_node.child(i) {
            if child.kind() == "parameter_declaration"
                || child.kind() == "variadic_parameter_declaration"
            {
                let name = child
                    .child_by_field_name("name")
                    .map(|n| node_text(n, source))
                    .unwrap_or_default();
                let type_ann = child
                    .child_by_field_name("type")
                    .map(|n| node_text(n, source));
                let is_variadic = child.kind() == "variadic_parameter_declaration"
                    || (child.child_count() > 0
                        && child
                            .child(0)
                            .is_some_and(|c| c.kind() == "variadic_parameter_declaration"));

                if name.is_empty() {
                    // Go allows unnamed parameters (just types, e.g.
                    // `func f(int, string)`). Emit a positional placeholder so
                    // downstream consumers (gnexec) can still bind by index.
                    let placeholder = format!("_arg{}", params.len());
                    params.push(FunctionParam {
                        name: placeholder,
                        type_annotation: type_ann,
                        default_value: None,
                        is_variadic,
                        semantic_type: Default::default(),
                    });
                } else {
                    params.push(FunctionParam {
                        name,
                        type_annotation: type_ann,
                        default_value: None, // Go has no default params
                        is_variadic,
                        semantic_type: Default::default(),
                    });
                }
            }
        }
    }
}

fn extract_go_callees(node: &Node, source: &str, callees: &mut Vec<String>) {
    if node.kind() == "call_expression" {
        if let Some(func) = node.child_by_field_name("function") {
            let callee = node_text(func, source);
            if !callee.is_empty() && !callees.contains(&callee) {
                callees.push(callee);
            }
        }
    }
    for i in 0..node.child_count() {
        if let Some(child) = node.child(i) {
            if child.kind() != "function_declaration" && child.kind() != "func_literal" {
                extract_go_callees(&child, source, callees);
            }
        }
    }
}

fn node_text(node: Node, source: &str) -> String {
    source[node.start_byte()..node.end_byte()].to_string()
}

fn node_text_truncated(node: &Node, source: &str, max: usize) -> String {
    let full = &source[node.start_byte()..node.end_byte()];
    let first_line = full.lines().next().unwrap_or(full);
    if first_line.len() > max {
        let end = first_line
            .char_indices()
            .nth(max)
            .map(|(i, _)| i)
            .unwrap_or(first_line.len());
        format!("{}...", &first_line[..end])
    } else {
        first_line.to_string()
    }
}

// ─────────────────────────────────────────────────────────────────────────────
// Semantic expression IR for orchestration mode.
//
// Mirrors the TypeScript / Python extractors. Walks tree-sitter-go expression
// nodes and emits the canonical JSON IR shape so downstream walkers (notably
// gnexec) can evaluate without re-parsing source. Unrecognised shapes fall
// back to `{ "kind": "raw", "text": <source> }` so the GG remains complete.
// ─────────────────────────────────────────────────────────────────────────────

/// Build orchestration-only properties for a Go `return_statement`.
///
/// Single-expression returns delegate to the shared helper and layer on
/// `callee`/`args` for `return foo(...)`. Multi-value returns emit an `array`
/// IR (Go allows `return a, b, c`).
fn build_return_props_go(node: &Node, source: &str) -> BTreeMap<String, String> {
    let mut cursor = node.walk();
    let expr_list = node
        .named_children(&mut cursor)
        .find(|c| c.kind() == "expression_list");
    let Some(expr_list) = expr_list else {
        return BTreeMap::new();
    };

    let mut list_cursor = expr_list.walk();
    let exprs: Vec<Node> = expr_list
        .named_children(&mut list_cursor)
        .filter(|c| !is_go_skip(c))
        .collect();

    if exprs.is_empty() {
        return BTreeMap::new();
    }

    let ir = if exprs.len() == 1 {
        go_node_to_ir(&exprs[0], source)
    } else {
        let items: Vec<serde_json::Value> =
            exprs.iter().map(|n| go_node_to_ir(n, source)).collect();
        serde_json::json!({ "kind": "array", "items": items })
    };

    let mut props = ir_build_return_props(ir.clone());
    if let Some((callee, args)) = ir_call_callee_args(&ir) {
        props.insert("callee".to_string(), callee);
        if let Ok(args_json) = serde_json::to_string(&args) {
            props.insert("args".to_string(), args_json);
        }
    }
    props
}

/// Build orchestration-only properties for a Go `expression_statement`.
fn build_expression_statement_props_go(node: &Node, source: &str) -> BTreeMap<String, String> {
    let mut cursor = node.walk();
    let inner = node
        .named_children(&mut cursor)
        .find(|child| !is_go_skip(child));
    let Some(inner) = inner else {
        return BTreeMap::new();
    };
    let ir = go_node_to_ir(&inner, source);
    ir_build_expression_statement_props(ir, None, None)
}

/// Build orchestration-only properties for `short_var_declaration`,
/// `var_declaration`, and `assignment_statement`.
fn build_go_declaration_props(node: &Node, source: &str) -> BTreeMap<String, String> {
    let kind = node.kind();
    match kind {
        "short_var_declaration" | "assignment_statement" => {
            build_go_assignment_like_props(node, source)
        }
        "var_declaration" => build_go_var_declaration_props(node, source),
        _ => BTreeMap::new(),
    }
}

fn build_go_assignment_like_props(node: &Node, source: &str) -> BTreeMap<String, String> {
    let left = node.child_by_field_name("left");
    let right = node.child_by_field_name("right");

    let lhs_exprs: Vec<Node> = left
        .map(|l| {
            let mut cur = l.walk();
            l.named_children(&mut cur)
                .filter(|c| !is_go_skip(c))
                .collect()
        })
        .unwrap_or_default();
    let rhs_exprs: Vec<Node> = right
        .map(|r| {
            let mut cur = r.walk();
            r.named_children(&mut cur)
                .filter(|c| !is_go_skip(c))
                .collect()
        })
        .unwrap_or_default();

    // Single binding `x := expr` / `x = expr` — reuse the shared helper.
    if lhs_exprs.len() == 1 && rhs_exprs.len() == 1 {
        let bind_ir = go_node_to_ir(&lhs_exprs[0], source);
        let value_ir = go_node_to_ir(&rhs_exprs[0], source);
        if let Some(simple) = ir_as_simple_ident(&bind_ir) {
            return ir_build_declaration_props(&simple, value_ir);
        }
        // Non-simple lvalue (e.g. `obj.field = ...`, `arr[i] = ...`).
        let mut props = BTreeMap::new();
        if let Ok(s) = serde_json::to_string(&bind_ir) {
            props.insert("bind_target".to_string(), s);
        }
        if let Ok(s) = serde_json::to_string(&value_ir) {
            props.insert("expr".to_string(), s);
        }
        if let Some((callee, args)) = ir_call_callee_args(&value_ir) {
            props.insert("callee".to_string(), callee);
            if let Ok(args_json) = serde_json::to_string(&args) {
                props.insert("args".to_string(), args_json);
            }
        }
        return props;
    }

    // Multi-binding: `f, err := os.Open(...)` or `a, b = b, a`.
    let mut props = BTreeMap::new();
    let lhs_irs: Vec<serde_json::Value> =
        lhs_exprs.iter().map(|n| go_node_to_ir(n, source)).collect();
    if !lhs_irs.is_empty() {
        let pattern = serde_json::json!({ "kind": "array_pattern", "items": lhs_irs });
        if let Ok(s) = serde_json::to_string(&pattern) {
            props.insert("bind_pattern".to_string(), s);
        }
    }
    let rhs_ir = if rhs_exprs.len() == 1 {
        go_node_to_ir(&rhs_exprs[0], source)
    } else {
        let items: Vec<serde_json::Value> =
            rhs_exprs.iter().map(|n| go_node_to_ir(n, source)).collect();
        serde_json::json!({ "kind": "array", "items": items })
    };
    if let Ok(s) = serde_json::to_string(&rhs_ir) {
        props.insert("expr".to_string(), s);
    }
    if let Some((callee, args)) = ir_call_callee_args(&rhs_ir) {
        props.insert("callee".to_string(), callee);
        if let Ok(args_json) = serde_json::to_string(&args) {
            props.insert("args".to_string(), args_json);
        }
    }
    props
}

fn build_go_var_declaration_props(node: &Node, source: &str) -> BTreeMap<String, String> {
    // `var x = expr` / `var x int = expr`. Multi-spec var blocks fall back to
    // the first spec — matches per-statement CFG granularity.
    let mut cursor = node.walk();
    let spec = node
        .named_children(&mut cursor)
        .find(|c| c.kind() == "var_spec");
    let Some(spec) = spec else {
        return BTreeMap::new();
    };

    let mut name_cursor = spec.walk();
    let names: Vec<Node> = spec
        .children_by_field_name("name", &mut name_cursor)
        .collect();
    let value_node = spec.child_by_field_name("value");
    let value_exprs: Vec<Node> = value_node
        .map(|v| {
            let mut cur = v.walk();
            v.named_children(&mut cur)
                .filter(|c| !is_go_skip(c))
                .collect()
        })
        .unwrap_or_default();

    if names.len() == 1 && value_exprs.len() == 1 {
        let bind_name = node_text(names[0], source);
        let value_ir = go_node_to_ir(&value_exprs[0], source);
        return ir_build_declaration_props(&bind_name, value_ir);
    }
    if names.len() == 1 && value_exprs.is_empty() {
        let mut props = BTreeMap::new();
        props.insert("bind".to_string(), node_text(names[0], source));
        return props;
    }

    // Multi-name var spec.
    let mut props = BTreeMap::new();
    if !names.is_empty() {
        let items: Vec<serde_json::Value> = names
            .iter()
            .map(|n| serde_json::json!({ "kind": "ident", "name": node_text(*n, source) }))
            .collect();
        let pattern = serde_json::json!({ "kind": "array_pattern", "items": items });
        if let Ok(s) = serde_json::to_string(&pattern) {
            props.insert("bind_pattern".to_string(), s);
        }
    }
    if !value_exprs.is_empty() {
        let value_ir = if value_exprs.len() == 1 {
            go_node_to_ir(&value_exprs[0], source)
        } else {
            let items: Vec<serde_json::Value> = value_exprs
                .iter()
                .map(|n| go_node_to_ir(n, source))
                .collect();
            serde_json::json!({ "kind": "array", "items": items })
        };
        if let Ok(s) = serde_json::to_string(&value_ir) {
            props.insert("expr".to_string(), s);
        }
        if let Some((callee, args)) = ir_call_callee_args(&value_ir) {
            props.insert("callee".to_string(), callee);
            if let Ok(args_json) = serde_json::to_string(&args) {
                props.insert("args".to_string(), args_json);
            }
        }
    }
    props
}

/// Convert a tree-sitter-go expression node into the orchestration IR.
fn go_node_to_ir(node: &Node, source: &str) -> serde_json::Value {
    use serde_json::{json, Number, Value};
    let kind = node.kind();
    match kind {
        "int_literal" => {
            let text = node_text(*node, source);
            let cleaned = text.replace('_', "");
            let value = if let Ok(i) = cleaned.parse::<i64>() {
                Value::Number(Number::from(i))
            } else if let Some(stripped) = cleaned
                .strip_prefix("0x")
                .or_else(|| cleaned.strip_prefix("0X"))
            {
                i64::from_str_radix(stripped, 16)
                    .ok()
                    .map(|n| Value::Number(Number::from(n)))
                    .unwrap_or(Value::String(text.clone()))
            } else if let Some(stripped) = cleaned
                .strip_prefix("0o")
                .or_else(|| cleaned.strip_prefix("0O"))
            {
                i64::from_str_radix(stripped, 8)
                    .ok()
                    .map(|n| Value::Number(Number::from(n)))
                    .unwrap_or(Value::String(text.clone()))
            } else if let Some(stripped) = cleaned
                .strip_prefix("0b")
                .or_else(|| cleaned.strip_prefix("0B"))
            {
                i64::from_str_radix(stripped, 2)
                    .ok()
                    .map(|n| Value::Number(Number::from(n)))
                    .unwrap_or(Value::String(text.clone()))
            } else {
                Value::String(text.clone())
            };
            json!({ "kind": "literal", "value": value })
        }
        "float_literal" => {
            let text = node_text(*node, source);
            let cleaned = text.replace('_', "");
            let value = cleaned
                .parse::<f64>()
                .ok()
                .and_then(Number::from_f64)
                .map(Value::Number)
                .unwrap_or(Value::String(text));
            json!({ "kind": "literal", "value": value })
        }
        "imaginary_literal" => json!({ "kind": "raw", "text": node_text(*node, source) }),
        "rune_literal" => json!({ "kind": "literal", "value": node_text(*node, source) }),
        "true" => json!({ "kind": "literal", "value": true }),
        "false" => json!({ "kind": "literal", "value": false }),
        "nil" => json!({ "kind": "literal", "value": Value::Null }),
        "interpreted_string_literal" | "raw_string_literal" => {
            let s = go_string_literal_value(node, source);
            json!({ "kind": "literal", "value": s })
        }
        "identifier" | "field_identifier" | "package_identifier" | "type_identifier" => {
            json!({ "kind": "ident", "name": node_text(*node, source) })
        }
        "parenthesized_expression" => {
            let mut cursor = node.walk();
            for child in node.named_children(&mut cursor) {
                if !is_go_skip(&child) {
                    return go_node_to_ir(&child, source);
                }
            }
            json!({ "kind": "raw", "text": node_text(*node, source) })
        }
        "selector_expression" => {
            let obj = node
                .child_by_field_name("operand")
                .map(|n| go_node_to_ir(&n, source))
                .unwrap_or(Value::Null);
            let prop = node
                .child_by_field_name("field")
                .map(|n| node_text(n, source))
                .unwrap_or_default();
            json!({ "kind": "member", "obj": obj, "prop": prop })
        }
        "index_expression" => {
            let obj = node
                .child_by_field_name("operand")
                .map(|n| go_node_to_ir(&n, source))
                .unwrap_or(Value::Null);
            let key = node
                .child_by_field_name("index")
                .map(|n| go_node_to_ir(&n, source))
                .unwrap_or(Value::Null);
            // Canonicalize map reads with a plain literal-string key
            // (`input["name"]`) to `member` IR — the property-carried shape
            // TS `input.name` lowers to, so downstream walkers evaluate the
            // access without Go-specific index semantics. Dynamic or
            // non-field-shaped keys keep the `index` form.
            if key.get("kind").and_then(Value::as_str) == Some("literal") {
                if let Some(field) = key.get("value").and_then(Value::as_str) {
                    if crate::extractors::ir::is_plain_field_name(field) {
                        return json!({ "kind": "member", "obj": obj, "prop": field });
                    }
                }
            }
            json!({ "kind": "index", "obj": obj, "key": key })
        }
        "call_expression" => {
            let func = node.child_by_field_name("function");
            let callee_value = match &func {
                Some(f) if f.kind() == "identifier" => Value::String(node_text(*f, source)),
                Some(f) => go_node_to_ir(f, source),
                None => Value::Null,
            };
            let mut args: Vec<Value> = Vec::new();
            if let Some(args_node) = node.child_by_field_name("arguments") {
                let mut cursor = args_node.walk();
                for child in args_node.named_children(&mut cursor) {
                    if is_go_skip(&child) {
                        continue;
                    }
                    if child.kind() == "variadic_argument" {
                        let mut inner_cursor = child.walk();
                        let inner = child
                            .named_children(&mut inner_cursor)
                            .find(|c| !is_go_skip(c));
                        let inner_ir = inner
                            .map(|n| go_node_to_ir(&n, source))
                            .unwrap_or(Value::Null);
                        args.push(json!({ "kind": "spread", "arg": inner_ir }));
                    } else {
                        args.push(go_node_to_ir(&child, source));
                    }
                }
            }
            // Canonicalize `fmt.Sprintf("…%s…", args…)` with only plain
            // string verbs into `template` IR — the shape TS template
            // literals lower to — so property-carried walkers evaluate the
            // format without knowing fmt. Non-%s/%v verbs (widths, %d, %%)
            // keep the call form.
            if let Some(template) = go_sprintf_to_template_ir(&callee_value, &args) {
                return template;
            }
            json!({ "kind": "call", "callee": callee_value, "args": args })
        }
        "binary_expression" => {
            let lhs = node
                .child_by_field_name("left")
                .map(|n| go_node_to_ir(&n, source))
                .unwrap_or(Value::Null);
            let rhs = node
                .child_by_field_name("right")
                .map(|n| go_node_to_ir(&n, source))
                .unwrap_or(Value::Null);
            let op = node
                .child_by_field_name("operator")
                .map(|n| node_text(n, source))
                .unwrap_or_default();
            // Canonicalize provably-string `+` chains (`"hello:" + name`)
            // to `template` IR, mirroring the fmt.Sprintf lowering above.
            if op == "+" {
                if let Some(template) =
                    crate::extractors::ir::concat_chain_to_template(&lhs, &rhs)
                {
                    return template;
                }
            }
            json!({ "kind": "binary", "op": op, "lhs": lhs, "rhs": rhs })
        }
        "unary_expression" => {
            let arg = node
                .child_by_field_name("operand")
                .map(|n| go_node_to_ir(&n, source))
                .unwrap_or(Value::Null);
            let op = node
                .child_by_field_name("operator")
                .map(|n| node_text(n, source))
                .unwrap_or_default();
            json!({ "kind": "unary", "op": op, "arg": arg })
        }
        "composite_literal" => go_composite_literal_to_ir(node, source),
        _ => json!({ "kind": "raw", "text": node_text(*node, source) }),
    }
}

/// Lower `fmt.Sprintf(format, args…)` to `template` IR when — and only
/// when — the format is a literal string whose verbs are all bare `%s`/`%v`
/// and the verb count matches the argument count. Everything else (other
/// verbs, `%%` escapes, widths/flags, dynamic formats, arity mismatch)
/// returns `None` and keeps the plain call IR: fail-closed canonicalization.
fn go_sprintf_to_template_ir(
    callee: &serde_json::Value,
    args: &[serde_json::Value],
) -> Option<serde_json::Value> {
    use serde_json::{json, Value};
    // Callee must be exactly `fmt.Sprintf`.
    if callee.get("kind").and_then(Value::as_str) != Some("member")
        || callee.get("prop").and_then(Value::as_str) != Some("Sprintf")
        || callee
            .get("obj")
            .and_then(|o| o.get("name"))
            .and_then(Value::as_str)
            != Some("fmt")
    {
        return None;
    }
    let (format_ir, value_args) = args.split_first()?;
    if format_ir.get("kind").and_then(Value::as_str) != Some("literal") {
        return None;
    }
    let format = format_ir.get("value").and_then(Value::as_str)?;

    let mut parts: Vec<Value> = Vec::new();
    let mut text = String::new();
    let mut values = value_args.iter();
    let mut chars = format.chars();
    while let Some(c) = chars.next() {
        if c != '%' {
            text.push(c);
            continue;
        }
        match chars.next() {
            Some('s') | Some('v') => {
                if !text.is_empty() {
                    parts.push(json!({ "kind": "text", "s": std::mem::take(&mut text) }));
                }
                let value = values.next()?; // more verbs than args → keep call IR
                parts.push(json!({ "kind": "expr", "e": value }));
            }
            // Any other verb (including `%%`) is outside the canonical subset.
            _ => return None,
        }
    }
    if values.next().is_some() {
        return None; // more args than verbs → keep call IR
    }
    if !text.is_empty() {
        parts.push(json!({ "kind": "text", "s": text }));
    }
    Some(json!({ "kind": "template", "parts": parts }))
}

/// Convert a Go `composite_literal` to IR. Slice/array → `array`; struct → `object`
/// (field initializers); map → `object` with stringified keys.
fn go_composite_literal_to_ir(node: &Node, source: &str) -> serde_json::Value {
    use serde_json::{json, Value};
    let type_node = node.child_by_field_name("type");
    let type_kind = type_node.map(|n| n.kind());
    let body = match node.child_by_field_name("body") {
        Some(b) => b,
        None => return json!({ "kind": "raw", "text": node_text(*node, source) }),
    };

    let is_array_like = matches!(
        type_kind,
        Some("array_type") | Some("slice_type") | Some("implicit_length_array_type")
    );
    let is_map = matches!(type_kind, Some("map_type"));

    let mut cursor = body.walk();
    let elements: Vec<Node> = body
        .named_children(&mut cursor)
        .filter(|c| !is_go_skip(c))
        .collect();

    if is_array_like {
        let mut items: Vec<Value> = Vec::new();
        for el in &elements {
            if el.kind() == "keyed_element" {
                let v = el
                    .child_by_field_name("value")
                    .map(|n| go_literal_element_to_ir(&n, source))
                    .unwrap_or(Value::Null);
                items.push(v);
            } else {
                items.push(go_literal_element_to_ir(el, source));
            }
        }
        return json!({ "kind": "array", "items": items });
    }

    // Struct or map → object.
    let mut fields: Vec<Value> = Vec::new();
    let mut all_keyed = true;
    for el in &elements {
        if el.kind() == "keyed_element" {
            let key_node = el.child_by_field_name("key");
            let value_node = el.child_by_field_name("value");
            if let (Some(k), Some(v)) = (key_node, value_node) {
                let key_inner = go_unwrap_literal_element(&k);
                let key_text = if is_map {
                    match key_inner.kind() {
                        "interpreted_string_literal" | "raw_string_literal" => {
                            go_string_literal_value(&key_inner, source)
                        }
                        _ => {
                            all_keyed = false;
                            break;
                        }
                    }
                } else {
                    node_text(key_inner, source)
                };
                let value_ir = go_literal_element_to_ir(&v, source);
                fields.push(json!({ "k": key_text, "v": value_ir }));
                continue;
            }
            all_keyed = false;
            break;
        } else {
            all_keyed = false;
            break;
        }
    }
    if all_keyed {
        json!({ "kind": "object", "fields": fields })
    } else {
        json!({ "kind": "raw", "text": node_text(*node, source) })
    }
}

/// `literal_element` wraps a single expression. Unwrap and convert.
fn go_literal_element_to_ir(node: &Node, source: &str) -> serde_json::Value {
    if node.kind() == "literal_element" {
        let mut cursor = node.walk();
        for child in node.named_children(&mut cursor) {
            if !is_go_skip(&child) {
                return go_node_to_ir(&child, source);
            }
        }
    }
    go_node_to_ir(node, source)
}

fn go_unwrap_literal_element<'a>(node: &Node<'a>) -> Node<'a> {
    if node.kind() == "literal_element" {
        let mut cursor = node.walk();
        for child in node.named_children(&mut cursor) {
            if !is_go_skip(&child) {
                return child;
            }
        }
    }
    *node
}

/// Strip surrounding quotes / backticks from a Go string node.
fn go_string_literal_value(node: &Node, source: &str) -> String {
    if node.kind() == "raw_string_literal" {
        let raw = node_text(*node, source);
        return raw
            .strip_prefix('`')
            .and_then(|s| s.strip_suffix('`'))
            .map(str::to_string)
            .unwrap_or(raw);
    }
    let mut out = String::new();
    let mut cursor = node.walk();
    for child in node.named_children(&mut cursor) {
        if child.kind() == "interpreted_string_literal_content" || child.kind() == "escape_sequence"
        {
            out.push_str(&node_text(child, source));
        }
    }
    if !out.is_empty() {
        return out;
    }
    let raw = node_text(*node, source);
    raw.strip_prefix('"')
        .and_then(|s| s.strip_suffix('"'))
        .map(str::to_string)
        .unwrap_or(raw)
}

/// Skip predicate for Go AST traversal.
fn is_go_skip(node: &Node) -> bool {
    matches!(node.kind(), "comment")
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn extracts_go_function() {
        let source = r#"
package main

func processData(data []byte) error {
    if len(data) == 0 {
        return fmt.Errorf("empty data")
    }
    f, err := os.Open("input.txt")
    if err != nil {
        return err
    }
    defer f.Close()
    return nil
}
"#;

        let extractor = GoExtractor;
        let cfgs = extractor.extract(source, "test.go").unwrap();
        assert_eq!(cfgs.len(), 1);
        assert_eq!(cfgs[0].function_name, "processData");
    }

    /// Find the first Branch node carrying an `expr` property and return it.
    /// Skips merges/statements; useful for switch-lowering assertions.
    fn first_branch_expr(cfg: &ControlFlowGraph) -> Option<String> {
        cfg.nodes.iter().find_map(|n| {
            if matches!(n.kind, CfgNodeKind::Branch { .. }) {
                n.extra_properties.get("expr").cloned()
            } else {
                None
            }
        })
    }

    fn nth_branch_expr(cfg: &ControlFlowGraph, n: usize) -> Option<String> {
        cfg.nodes
            .iter()
            .filter(|node| matches!(node.kind, CfgNodeKind::Branch { .. }))
            .nth(n)
            .and_then(|node| node.extra_properties.get("expr").cloned())
    }

    #[test]
    fn switch_multi_value_case_emits_or_chain() {
        let source = r#"
package main

func statusMessage(code int) string {
	switch code {
	case 401, 403:
		return "auth"
	case 404:
		return "missing"
	default:
		return "ok"
	}
}
"#;
        let extractor = GoExtractor;
        let cfgs = extractor.extract(source, "test.go").unwrap();
        let cfg = &cfgs[0];

        // First branch is `case 401, 403` — must be an OR of two equality
        // checks against `code`, not a raw-text rhs.
        let first = first_branch_expr(cfg).expect("first branch should carry expr");
        let v: serde_json::Value = serde_json::from_str(&first).unwrap();
        assert_eq!(v["kind"], "binary", "expected top-level binary");
        assert_eq!(v["op"], "||", "multi-value case must left-fold to OR");

        let lhs = &v["lhs"];
        assert_eq!(lhs["op"], "===");
        assert_eq!(lhs["lhs"]["kind"], "ident");
        assert_eq!(lhs["lhs"]["name"], "code");
        assert_eq!(lhs["rhs"]["value"], 401);

        let rhs = &v["rhs"];
        assert_eq!(rhs["op"], "===");
        assert_eq!(rhs["rhs"]["value"], 403);

        // Second branch (`case 404`) must remain a plain equality, not OR.
        let second = nth_branch_expr(cfg, 1).expect("second branch missing");
        let v2: serde_json::Value = serde_json::from_str(&second).unwrap();
        assert_eq!(v2["op"], "===");
        assert_eq!(v2["rhs"]["value"], 404);
    }

    #[test]
    fn switch_three_value_case_left_folds_or() {
        let source = r#"
package main

func bucket(code int) string {
	switch code {
	case 500, 502, 503:
		return "server"
	default:
		return "ok"
	}
}
"#;
        let extractor = GoExtractor;
        let cfgs = extractor.extract(source, "test.go").unwrap();
        let first = first_branch_expr(&cfgs[0]).expect("branch missing");
        let v: serde_json::Value = serde_json::from_str(&first).unwrap();
        // Left-fold: ((500 || 502) || 503)
        assert_eq!(v["op"], "||");
        assert_eq!(v["rhs"]["op"], "===");
        assert_eq!(v["rhs"]["rhs"]["value"], 503);
        assert_eq!(v["lhs"]["op"], "||");
        assert_eq!(v["lhs"]["lhs"]["rhs"]["value"], 500);
        assert_eq!(v["lhs"]["rhs"]["rhs"]["value"], 502);
    }

    #[test]
    fn tagless_switch_emits_inner_expression_directly() {
        let source = r#"
package main

func categoryFor(x int, y int) string {
	switch {
	case x < y:
		return "less"
	case x > y:
		return "more"
	default:
		return "eq"
	}
}
"#;
        let extractor = GoExtractor;
        let cfgs = extractor.extract(source, "test.go").unwrap();
        let cfg = &cfgs[0];

        let first = first_branch_expr(cfg).expect("first branch missing");
        let v: serde_json::Value = serde_json::from_str(&first).unwrap();
        // Tag-less switch: emit the inner boolean directly. No `===` wrap,
        // and no `null` lhs poisoning.
        assert_eq!(v["kind"], "binary");
        assert_eq!(v["op"], "<", "tag-less case must surface its own operator");
        assert_eq!(v["lhs"]["kind"], "ident");
        assert_eq!(v["lhs"]["name"], "x");
        assert_eq!(v["rhs"]["kind"], "ident");
        assert_eq!(v["rhs"]["name"], "y");
        assert!(
            v.get("lhs")
                .and_then(|l| l.as_null().map(|_| true))
                .is_none(),
            "tag-less switch must not emit `null === expr`"
        );

        let second = nth_branch_expr(cfg, 1).expect("second branch missing");
        let v2: serde_json::Value = serde_json::from_str(&second).unwrap();
        assert_eq!(v2["op"], ">");
    }

    #[test]
    fn detects_goroutine_spawn() {
        let source = r#"
package main

func startWorkers() {
    go worker()
    go func() {
        process()
    }()
}
"#;

        let extractor = GoExtractor;
        let cfgs = extractor.extract(source, "test.go").unwrap();
        let spawn_count = cfgs[0]
            .nodes
            .iter()
            .filter(|n| matches!(n.kind, CfgNodeKind::ConcurrentSpawn))
            .count();
        assert!(spawn_count >= 1, "should detect goroutine spawns");
    }
}
